'use client';

import { useLexstudioStore } from '@/lib/store';
import { PreviewTab } from '@/lib/types';
import ReactMarkdown from 'react-markdown';
import { useEffect, useRef, useState } from 'react';
import Editor from 'react-simple-code-editor';
import { Prism } from 'prism-react-renderer';

// ERC-3643 T-REX initial template
const ERC3643_TEMPLATE = `// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.20;

// ERC-3643 T-REX RWA Token — Generated by Lexstudio
// Replace /* PLACEHOLDER */ comments before deployment

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

contract /* TOKEN_NAME */ is Ownable, Pausable {
    string public name = "/* TOKEN_FULL_NAME */";
    string public symbol = "/* TOKEN_SYMBOL */";
    uint8 public decimals = 18;
    uint256 public totalSupply = /* TOTAL_SUPPLY */;

    address public identityRegistry;  // /* IDENTITY_REGISTRY_ADDRESS */
    address public compliance;        // /* COMPLIANCE_MODULE_ADDRESS */

    mapping(address => uint256) private _balances;
    mapping(address => bool) public frozen;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event TokensFrozen(address indexed wallet);
    event TokensUnfrozen(address indexed wallet);

    modifier onlyVerifiedInvestor(address _to) {
        // Identity check via IIdentityRegistry
        _;
    }

    function transfer(address to, uint256 amount)
        public whenNotPaused onlyVerifiedInvestor(to) returns (bool) {
        // Compliance check before transfer
        _transfer(msg.sender, to, amount);
        return true;
    }

    function mint(address to, uint256 amount) external onlyOwner {
        // /* MINTING_AUTHORITY_CHECK */
        _balances[to] += amount;
        totalSupply += amount;
        emit Transfer(address(0), to, amount);
    }

    function freeze(address wallet) external onlyOwner {
        frozen[wallet] = true;
        emit TokensFrozen(wallet);
    }

    function _transfer(address from, address to, uint256 amount) internal {
        require(!frozen[from], "Sender frozen");
        require(!frozen[to], "Recipient frozen");
        require(_balances[from] >= amount, "Insufficient balance");
        _balances[from] -= amount;
        _balances[to] += amount;
        emit Transfer(from, to, amount);
    }
}`;

// Default Mermaid arch map template
const ARCH_MAP_TEMPLATE = `graph TD
  Investor([Investor]) -->|KYC/AML| IR[Identity Registry]
  IR -->|Verified| Token["ERC-3643 Token\n/* TOKEN_SYMBOL */"]
  Token -->|Transfer Check| CM[Compliance Module]
  CM -->|/* JURISDICTION */ Rules| JR[(Rule Engine)]
  Token -->|NAV Feed| Oracle[Price Oracle]
  Issuer([/* ISSUER_NAME */]) -->|Mint/Burn| Token
  Token -->|Yield| Investor`;

// Solidity keyword highlight using prism-react-renderer's Prism (clike base)
function highlightSolidity(code: string): string {
  try {
    // Use clike grammar which handles most Solidity syntax
    const grammar = Prism.languages.clike || Prism.languages.javascript;
    if (!grammar) return escapeHtml(code);
    const tokens = Prism.tokenize(code, grammar);
    return tokensToHtml(tokens);
  } catch {
    return escapeHtml(code);
  }
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

// Additional Solidity-specific keyword coloring via regex on top of prism output
function tokensToHtml(tokens: (string | Prism.Token)[]): string {
  return tokens.map(token => {
    if (typeof token === 'string') return escapeHtml(token);
    const content = Array.isArray(token.content)
      ? tokensToHtml(token.content as (string | Prism.Token)[])
      : typeof token.content === 'string'
        ? escapeHtml(token.content)
        : '';
    return `<span class="token ${token.type}">${content}</span>`;
  }).join('');
}

export function PreviewCard() {
  const previewTab = useLexstudioStore((state) => state.previewTab);
  const setPreviewTab = useLexstudioStore((state) => state.setPreviewTab);
  const whitepaperContent = useLexstudioStore((state) => state.whitepaperContent);
  const contractContent = useLexstudioStore((state) => state.contractContent);
  const archMapContent = useLexstudioStore((state) => state.archMapContent);
  const updateContract = useLexstudioStore((state) => state.updateContract);
  const contractDiff = useLexstudioStore((state) => state.contractDiff);

  const mermaidRef = useRef<HTMLDivElement>(null);
  const [mermaidSvg, setMermaidSvg] = useState<string>('');
  const [mermaidError, setMermaidError] = useState<string>('');

  const displayContract = contractContent || ERC3643_TEMPLATE;
  const displayArchMap = archMapContent || ARCH_MAP_TEMPLATE;

  // Render mermaid diagram
  useEffect(() => {
    if (previewTab !== 'arch-map') return;

    let cancelled = false;
    const renderMermaid = async () => {
      try {
        const mermaid = (await import('mermaid')).default;
        mermaid.initialize({
          startOnLoad: false,
          theme: 'base',
          themeVariables: {
            primaryColor: '#E1E9F6',
            primaryTextColor: '#000000',
            primaryBorderColor: '#324998',
            lineColor: '#324998',
            secondaryColor: '#f0f2f5',
            tertiaryColor: '#ffffff',
          },
        });

        const id = `arch-map-${Date.now()}`;
        const { svg } = await mermaid.render(id, displayArchMap);
        if (!cancelled) {
          setMermaidSvg(svg);
          setMermaidError('');
        }
      } catch (err) {
        if (!cancelled) {
          setMermaidError('Failed to render diagram. Check the Mermaid syntax.');
          console.error('Mermaid render error:', err);
        }
      }
    };

    renderMermaid();
    return () => { cancelled = true; };
  }, [previewTab, displayArchMap]);

  const tabs: { id: PreviewTab; label: string }[] = [
    { id: 'whitepaper', label: 'Whitepaper' },
    { id: 'contract', label: 'Contract' },
    { id: 'arch-map', label: 'Arch-Map' },
  ];

  return (
    <div className="bg-white rounded-xl border border-[#E5E7EB] shadow-sm flex flex-col h-full overflow-hidden">
      {/* Tabs */}
      <div className="flex border-b border-gray-200 px-1 flex-shrink-0">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => setPreviewTab(tab.id)}
            className={`
              relative px-5 py-3 font-body text-sm font-medium
              transition-all duration-150
              ${previewTab === tab.id
                ? 'text-[#324998]'
                : 'text-gray-500 hover:text-gray-700'
              }
            `}
          >
            {tab.label}
            {previewTab === tab.id && (
              <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-[#324998]" />
            )}
          </button>
        ))}
      </div>

      {/* Content Area */}
      <div className="flex-1 overflow-y-auto">
        {/* ── Whitepaper Tab ── */}
        {previewTab === 'whitepaper' && (
          whitepaperContent ? (
            <div className="p-8 text-sm text-gray-700 leading-relaxed max-w-none">
              <ReactMarkdown
                components={{
                  h1: ({ children }) => (
                    <h1 className="text-center text-2xl font-bold text-black border-b border-[#E5E7EB] pb-4 mb-6 mt-2">
                      {children}
                    </h1>
                  ),
                  h2: ({ children }) => (
                    <h2 className="text-[#324998] border-l-4 border-[#324998] pl-3 mt-8 mb-3 text-base font-semibold">
                      {children}
                    </h2>
                  ),
                  h3: ({ children }) => (
                    <h3 className="text-gray-800 font-semibold mt-5 mb-2 text-sm">
                      {children}
                    </h3>
                  ),
                  p: ({ children }) => (
                    <p className="leading-relaxed text-gray-700 my-2">{children}</p>
                  ),
                  ul: ({ children }) => (
                    <ul className="list-disc list-inside my-2 space-y-0.5 text-gray-700">{children}</ul>
                  ),
                  ol: ({ children }) => (
                    <ol className="list-decimal list-inside my-2 space-y-0.5 text-gray-700">{children}</ol>
                  ),
                  li: ({ children }) => (
                    <li className="my-0.5 leading-relaxed">{children}</li>
                  ),
                  strong: ({ children }) => (
                    <strong className="font-semibold text-gray-900">{children}</strong>
                  ),
                  hr: () => <hr className="border-[#E5E7EB] my-4" />,
                  table: ({ children }) => (
                    <table className="w-full text-sm border-collapse my-3">{children}</table>
                  ),
                  th: ({ children }) => (
                    <th className="bg-gray-50 font-semibold text-left px-3 py-2 border border-[#E5E7EB]">{children}</th>
                  ),
                  td: ({ children }) => (
                    <td className="px-3 py-2 border border-[#E5E7EB]">{children}</td>
                  ),
                  code: ({ children }) => (
                    <code className="bg-gray-100 text-[#324998] px-1 py-0.5 rounded text-xs font-mono">{children}</code>
                  ),
                }}
              >
                {whitepaperContent}
              </ReactMarkdown>
            </div>
          ) : (
            <EmptyState message="Whitepaper content will appear here as you progress through the steps" />
          )
        )}

        {/* ── Contract Tab ── */}
        {previewTab === 'contract' && (
          <div className="h-full flex flex-col">
            {/* Prism token color styles injected inline */}
            <style>{`
              .token.keyword    { color: #7c3aed; font-weight: 600; }
              .token.function   { color: #2563eb; }
              .token.string     { color: #16a34a; }
              .token.comment    { color: #9ca3af; font-style: italic; }
              .token.number     { color: #ea580c; }
              .token.operator   { color: #db2777; }
              .token.punctuation{ color: #374151; }
              .token.class-name { color: #d97706; font-weight: 600; }
              .token.boolean    { color: #dc2626; }
              .token.builtin    { color: #0891b2; }
            `}</style>
            <ContractEditor
              code={displayContract}
              onChange={updateContract}
              diff={contractDiff}
            />
          </div>
        )}

        {/* ── Arch-Map Tab ── */}
        {previewTab === 'arch-map' && (
          <div className="p-6 flex flex-col items-center" ref={mermaidRef}>
            {mermaidError ? (
              <div className="text-red-500 text-sm font-mono p-4 bg-red-50 rounded-lg w-full">
                {mermaidError}
              </div>
            ) : mermaidSvg ? (
              <div
                className="w-full overflow-auto"
                dangerouslySetInnerHTML={{ __html: mermaidSvg }}
              />
            ) : (
              <div className="flex items-center justify-center h-40 text-gray-400">
                <span className="text-sm">Rendering diagram...</span>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

// ── Contract Editor with line numbers and diff highlight ──
function ContractEditor({
  code,
  onChange,
  diff,
}: {
  code: string;
  onChange: (value: string) => void;
  diff: { added: number[]; modified: number[] };
}) {
  const lines = code.split('\n');

  return (
    <div className="flex h-full overflow-auto font-mono text-[13px] leading-[1.6]">
      {/* Line Numbers + Diff Gutter */}
      <div className="flex-shrink-0 select-none text-right pr-3 pl-3 pt-4 pb-4 text-gray-400 bg-gray-50 border-r border-gray-200">
        {lines.map((_, idx) => {
          const isAdded = diff.added.includes(idx);
          const isModified = diff.modified.includes(idx);
          return (
            <div
              key={idx}
              className={`
                relative leading-[1.6] min-h-[1.6em]
                ${isAdded ? 'border-l-2 border-green-500 pl-1 text-green-600' : ''}
                ${isModified ? 'border-l-2 border-yellow-400 pl-1 text-yellow-600' : ''}
              `}
            >
              {idx + 1}
            </div>
          );
        })}
      </div>

      {/* Editor */}
      <div className="flex-1 overflow-auto">
        <Editor
          value={code}
          onValueChange={onChange}
          highlight={highlightSolidity}
          padding={16}
          style={{
            fontFamily: '"JetBrains Mono", "Fira Code", monospace',
            fontSize: 13,
            lineHeight: 1.6,
            minHeight: '100%',
            background: 'transparent',
          }}
          className="outline-none"
        />
      </div>
    </div>
  );
}

function EmptyState({ message }: { message: string }) {
  return (
    <div className="flex flex-col items-center justify-center h-full text-gray-400 p-8">
      <svg className="w-16 h-16 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path
          strokeLinecap="round"
          strokeLinejoin="round"
          strokeWidth={1.5}
          d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"
        />
      </svg>
      <p className="font-body text-center text-sm max-w-xs">{message}</p>
    </div>
  );
}
